function describeFilters(filters, system) {
  const parts = [];
  if (system === "dnd5e") {
    if (filters.challengeRating !== void 0) {
      if (typeof filters.challengeRating === "number") {
        parts.push(`CR ${filters.challengeRating}`);
      } else {
        const min = filters.challengeRating.min ?? 0;
        const max = filters.challengeRating.max ?? 30;
        parts.push(`CR ${min}-${max}`);
      }
    }
    if (filters.creatureType)
      parts.push(filters.creatureType);
    if (filters.size)
      parts.push(filters.size);
    if (filters.alignment)
      parts.push(filters.alignment);
    if (filters.hasLegendaryActions)
      parts.push("legendary");
    if (filters.spellcaster)
      parts.push("spellcaster");
  } else if (system === "pf2e") {
    if (filters.level !== void 0) {
      if (typeof filters.level === "number") {
        parts.push(`Level ${filters.level}`);
      } else {
        const min = filters.level.min ?? -1;
        const max = filters.level.max ?? 25;
        parts.push(`Level ${min}-${max}`);
      }
    }
    if (filters.creatureType)
      parts.push(filters.creatureType);
    if (filters.rarity)
      parts.push(filters.rarity);
    if (filters.size)
      parts.push(filters.size);
    if (filters.alignment)
      parts.push(filters.alignment);
    if (filters.traits && filters.traits.length > 0) {
      parts.push(`traits: ${filters.traits.join(", ")}`);
    }
    if (filters.hasSpells)
      parts.push("spellcaster");
  }
  return parts.length > 0 ? parts.join(", ") : "no filters";
}

